"""Plugin definitions for the registry system.

Each plugin has:
  - name (str): unique identifier
  - plugin_type (str): one of 'log', 'cache', 'auth', 'metrics', 'notify'
  - execute(data: dict) -> dict: process data and return result
  - health_check() -> bool: return True if plugin is healthy
"""


class LogPlugin:
    name = "logger"
    plugin_type = "log"

    def execute(self, data: dict) -> dict:
        msg = data.get("message", "")
        level = data.get("level", "INFO")
        return {
            "status": "logged",
            "entry": f"[{level}] {msg}",
            "plugin": self.name,
        }

    def health_check(self) -> bool:
        return True


class CachePlugin:
    name = "cache"
    plugin_type = "cache"

    def __init__(self):
        self._store = {}

    def execute(self, data: dict) -> dict:
        action = data.get("action", "get")
        key = data.get("key", "")
        if action == "set":
            self._store[key] = data.get("value")
            return {"status": "stored", "key": key, "plugin": self.name}
        elif action == "get":
            val = self._store.get(key)
            return {"status": "retrieved", "key": key, "value": val, "plugin": self.name}
        return {"status": "unknown_action", "plugin": self.name}

    def health_check(self) -> bool:
        return True


class AuthPlugin:
    name = "auth"
    plugin_type = "auth"

    def __init__(self):
        self._tokens = {"admin-token": "admin", "user-token": "user"}

    def execute(self, data: dict) -> dict:
        token = data.get("token", "")
        if token in self._tokens:
            return {
                "status": "authenticated",
                "role": self._tokens[token],
                "plugin": self.name,
            }
        return {"status": "denied", "plugin": self.name}

    def health_check(self) -> bool:
        return len(self._tokens) > 0


class MetricsPlugin:
    name = "metrics"
    plugin_type = "metrics"

    def __init__(self):
        self._counters = {}

    def execute(self, data: dict) -> dict:
        metric = data.get("metric", "default")
        value = data.get("value", 1)
        self._counters[metric] = self._counters.get(metric, 0) + value
        return {
            "status": "recorded",
            "metric": metric,
            "total": self._counters[metric],
            "plugin": self.name,
        }

    def health_check(self) -> bool:
        return True


class NotifyPlugin:
    name = "notify"
    plugin_type = "notify"

    def __init__(self):
        self._sent = []

    def execute(self, data: dict) -> dict:
        recipient = data.get("to", "unknown")
        message = data.get("message", "")
        self._sent.append({"to": recipient, "message": message})
        return {
            "status": "sent",
            "to": recipient,
            "total_sent": len(self._sent),
            "plugin": self.name,
        }

    def health_check(self) -> bool:
        return True

seed_files.registry.py:
"""Plugin registry with dispatch and stats.

Public API:
  class PluginRegistry:
      __init__(self, name: str)
      register(self, plugin) -> str
      unregister(self, plugin_name: str) -> bool
      dispatch(self, plugin_type: str, data: dict) -> list[dict]
      dispatch_single(self, plugin_name: str, data: dict) -> dict
      get_stats(self) -> dict
      health_check_all(self) -> dict
      list_plugins(self) -> list[str]
      get_plugin(self, name: str) -> object | None
"""


class PluginRegistry:
    """Central registry for managing and dispatching to plugins."""

    VALID_TYPES = ["log", "cache", "auth", "metrics", "notify"]

    def __init__(self, name: str):
        self.name = name
        self._plugins = {}  # name -> plugin instance
        self._dispatch_count = 0

    # ------------------------------------------------------------------ #
    #  register: validate and add a plugin                                #
    # ------------------------------------------------------------------ #
    def register(self, plugin) -> str:
        """Register a plugin. Returns a status message string."""
        # --- Inline validation (copy 1 of 3) ---
        if not hasattr(plugin, "name"):
            raise ValueError("Plugin must have a 'name' attribute")
        if not hasattr(plugin, "plugin_type"):
            raise ValueError("Plugin must have a 'plugin_type' attribute")
        if not hasattr(plugin, "execute"):
            raise ValueError("Plugin must have an 'execute' method")
        if not hasattr(plugin, "health_check"):
            raise ValueError("Plugin must have a 'health_check' method")
        if not callable(plugin.execute):
            raise ValueError("Plugin 'execute' must be callable")
        if not callable(plugin.health_check):
            raise ValueError("Plugin 'health_check' must be callable")

        # --- String-type check chain (should use isinstance) ---
        ptype = plugin.plugin_type
        if type(ptype).__name__ == "str":
            pass  # ok
        else:
            raise TypeError("plugin_type must be a string")

        pname = plugin.name
        if type(pname).__name__ == "str":
            pass  # ok
        else:
            raise TypeError("plugin name must be a string")

        # --- Giant if/elif to handle each plugin type ---
        if ptype == "log":
            if pname in self._plugins:
                return f"Plugin '{pname}' already registered"
            self._plugins[pname] = plugin
            return f"Registered log plugin '{pname}'"
        elif ptype == "cache":
            if pname in self._plugins:
                return f"Plugin '{pname}' already registered"
            self._plugins[pname] = plugin
            return f"Registered cache plugin '{pname}'"
        elif ptype == "auth":
            if pname in self._plugins:
                return f"Plugin '{pname}' already registered"
            self._plugins[pname] = plugin
            return f"Registered auth plugin '{pname}'"
        elif ptype == "metrics":
            if pname in self._plugins:
                return f"Plugin '{pname}' already registered"
            self._plugins[pname] = plugin
            return f"Registered metrics plugin '{pname}'"
        elif ptype == "notify":
            if pname in self._plugins:
                return f"Plugin '{pname}' already registered"
            self._plugins[pname] = plugin
            return f"Registered notify plugin '{pname}'"
        else:
            raise ValueError(
                f"Unknown plugin type '{ptype}'. Valid types: {self.VALID_TYPES}"
            )

    # ------------------------------------------------------------------ #
    #  unregister: remove a plugin by name                                #
    # ------------------------------------------------------------------ #
    def unregister(self, plugin_name: str) -> bool:
        """Remove a plugin by name. Returns True if removed, False if not found."""
        if plugin_name in self._plugins:
            del self._plugins[plugin_name]
            return True
        return False

    # ------------------------------------------------------------------ #
    #  dispatch: send data to all plugins of a given type                 #
    # ------------------------------------------------------------------ #
    def dispatch(self, plugin_type: str, data: dict) -> list:
        """Dispatch data to all plugins matching plugin_type. Returns list of results."""
        # --- Inline validation (copy 2 of 3) ---
        if type(plugin_type).__name__ != "str":
            raise TypeError("plugin_type must be a string")

        results = []
        # --- Nested string matching instead of dispatch table ---
        if plugin_type == "log":
            for pname, p in self._plugins.items():
                if p.plugin_type == "log":
                    result = p.execute(data)
                    self._dispatch_count += 1
                    results.append(result)
        elif plugin_type == "cache":
            for pname, p in self._plugins.items():
                if p.plugin_type == "cache":
                    result = p.execute(data)
                    self._dispatch_count += 1
                    results.append(result)
        elif plugin_type == "auth":
            for pname, p in self._plugins.items():
                if p.plugin_type == "auth":
                    result = p.execute(data)
                    self._dispatch_count += 1
                    results.append(result)
        elif plugin_type == "metrics":
            for pname, p in self._plugins.items():
                if p.plugin_type == "metrics":
                    result = p.execute(data)
                    self._dispatch_count += 1
                    results.append(result)
        elif plugin_type == "notify":
            for pname, p in self._plugins.items():
                if p.plugin_type == "notify":
                    result = p.execute(data)
                    self._dispatch_count += 1
                    results.append(result)
        else:
            raise ValueError(
                f"Unknown plugin type '{plugin_type}'. Valid types: {self.VALID_TYPES}"
            )
        return results

    # ------------------------------------------------------------------ #
    #  dispatch_single: send data to one specific plugin by name          #
    # ------------------------------------------------------------------ #
    def dispatch_single(self, plugin_name: str, data: dict) -> dict:
        """Dispatch data to a single plugin by name. Returns result dict."""
        # --- Inline validation (copy 3 of 3) ---
        if type(plugin_name).__name__ != "str":
            raise TypeError("plugin_name must be a string")

        if plugin_name not in self._plugins:
            raise KeyError(f"Plugin '{plugin_name}' not found")
        plugin = self._plugins[plugin_name]
        self._dispatch_count += 1
        return plugin.execute(data)

    # ------------------------------------------------------------------ #
    #  get_stats: build registry statistics                               #
    # ------------------------------------------------------------------ #
    def get_stats(self) -> dict:
        """Return registry statistics as a dict."""
        stats = {
            "registry_name": self.name,
            "total_plugins": len(self._plugins),
            "dispatch_count": self._dispatch_count,
            "plugins_by_type": {},
            "plugin_names": [],
            "healthy_count": 0,
            "unhealthy_count": 0,
        }

        # --- Copy-paste loop 1: count by type ---
        log_count = 0
        for pname, p in self._plugins.items():
            if p.plugin_type == "log":
                log_count += 1
        stats["plugins_by_type"]["log"] = log_count

        cache_count = 0
        for pname, p in self._plugins.items():
            if p.plugin_type == "cache":
                cache_count += 1
        stats["plugins_by_type"]["cache"] = cache_count

        auth_count = 0
        for pname, p in self._plugins.items():
            if p.plugin_type == "auth":
                auth_count += 1
        stats["plugins_by_type"]["auth"] = auth_count

        metrics_count = 0
        for pname, p in self._plugins.items():
            if p.plugin_type == "metrics":
                metrics_count += 1
        stats["plugins_by_type"]["metrics"] = metrics_count

        notify_count = 0
        for pname, p in self._plugins.items():
            if p.plugin_type == "notify":
                notify_count += 1
        stats["plugins_by_type"]["notify"] = notify_count

        # --- Copy-paste loop 2: collect names ---
        for pname in self._plugins:
            stats["plugin_names"].append(pname)
        stats["plugin_names"].sort()

        # --- Copy-paste loop 3: health counts ---
        for pname, p in self._plugins.items():
            if p.health_check():
                stats["healthy_count"] += 1
            else:
                stats["unhealthy_count"] += 1

        return stats

    # ------------------------------------------------------------------ #
    #  health_check_all: check health of every plugin                     #
    # ------------------------------------------------------------------ #
    def health_check_all(self) -> dict:
        """Run health checks on all plugins. Returns dict of name -> bool."""
        results = {}
        for pname, p in self._plugins.items():
            results[pname] = p.health_check()
        return results

    # ------------------------------------------------------------------ #
    #  list_plugins: return sorted list of plugin names                   #
    # ------------------------------------------------------------------ #
    def list_plugins(self) -> list:
        """Return sorted list of registered plugin names."""
        names = []
        for pname in self._plugins:
            names.append(pname)
        names.sort()
        return names

    # ------------------------------------------------------------------ #
    #  get_plugin: retrieve a plugin instance by name                     #
    # ------------------------------------------------------------------ #
    def get_plugin(self, name: str):
        """Get a plugin by name, or None if not found."""
        if name in self._plugins:
            return self._plugins[name]
        return None
